    {"nombre": "Migas Manchegas", "ccaa": "Castilla-La Mancha", "tiempo": "40 min", "dificultad": "Media", "raciones": "2-3P", "temporada": "Invierno", "precio": 3.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Pan duro humedecido y frito con chorizo, panceta y uvas.", "ingredientes": ["300 g de pan duro del día anterior", "100 g de chorizo en taquitos", "80 g de panceta en tiras", "4 dientes de ajo enteros", "1 cdta de pimentón dulce", "80 ml de AOVE", "Sal al gusto", "Uvas blancas frescas para servir", "Opcional: 1 huevo frito por persona"], "preparacion": ["Trocea el pan en trozos pequeños del tamaño de una lenteja.", "Humedece con agua salada poco a poco, removiendo. Reposa al menos 2 horas envuelto en paño.", "Fríe panceta y chorizo en sartén con un tercio del aceite. Reserva.", "Dora los ajos enteros aplastados en el mismo aceite.", "Aparta, añade pimentón y remueve. Incorpora las migas.", "Remueve 15-20 min para que queden sueltas, doradas y crujientes.", "Devuelve panceta y chorizo, mezcla 2-3 min. Sirve con uvas."]},
    {"nombre": "Gachas Manchegas", "ccaa": "Castilla-La Mancha", "tiempo": "30-40 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Invierno", "precio": 2.75, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Harina de almortas con panceta, chorizo y ajos.", "ingredientes": ["120 g de harina de almortas", "500-600 ml de agua", "3 dientes de ajo", "100 g de panceta", "1 chorizo pequeño", "1 cdta pimentón", "3-4 cucharadas de AOVE", "Sal"], "preparacion": ["Fríe los ajos en aceite hasta dorar. Reserva.", "Fríe panceta y chorizo. Reserva.", "En el aceite restante, tuesta la harina removiendo 10 min hasta tonalidad anaranjada.", "Aparta, añade pimentón y remueve.", "Añade agua caliente en hilo fino sin parar de remover hasta espesar.", "Sirve en la sartén con panceta, chorizo y ajos por encima."]},
    {"nombre": "Pisto Manchego", "ccaa": "Castilla-La Mancha", "tiempo": "45-55 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Verano", "precio": 3.0, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": True}, "descripcion": "Verduras de huerta sofritas con tomate.", "ingredientes": ["3 tomates maduros grandes", "1 pimiento rojo, 1 pimiento verde", "1 calabacín mediano", "1 cebolla, 2 dientes de ajo", "4 cucharadas de AOVE", "1 cdta de azúcar", "Sal y pimienta", "Opcional: huevo frito y pan"], "preparacion": ["Pica cebolla y ajo en daditos. Corta pimientos y calabacín.", "Sofríe cebolla y ajo 8 min a fuego medio.", "Añade pimientos y cocina 8 min más.", "Incorpora calabacín 5 min.", "Agrega tomate, azúcar, sal y pimienta. Cocina 25-30 min tapado.", "Destapa los últimos 10 min para evaporar el líquido.", "Sirve con huevo frito y pan."]},
    {"nombre": "Sopa Castellana", "ccaa": "Castilla y León", "tiempo": "30 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Invierno", "precio": 2.25, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Sopa reconfortante con pan, ajo, jamón y huevo escalfado.", "ingredientes": ["150 g de pan duro en rebanadas", "5 dientes de ajo laminados", "80 g de jamón serrano en taquitos", "1 cdta pimentón dulce", "600 ml de caldo de carne o pollo", "3 cucharadas de AOVE", "Sal y pimienta", "Huevos (1 por comensal)"], "preparacion": ["Dora los ajos laminados en aceite a fuego medio.", "Añade jamón y saltea 2-3 min.", "Incorpora pan y empapa de aceite.", "Aparta del fuego y añade pimentón. Remueve rápido.", "Vuelve al fuego y vierte el caldo caliente. Cuece a fuego suave 20 min.", "En los últimos 5 min, casca los huevos sobre la sopa. Tapa hasta cuajar la clara.", "Sirve inmediatamente en cuencos de barro."]},
    {"nombre": "Alubias con Morcilla", "ccaa": "Castilla y León", "tiempo": "2h30", "dificultad": "Media", "raciones": "2-3P", "temporada": "Invierno", "precio": 5.75, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Plato tradicional de legumbres con embutidos castellanos.", "ingredientes": ["250 g de judiones de La Granja", "1 morcilla de Burgos", "1 chorizo semicurado", "80 g de panceta ahumada", "½ cebolla, 3 ajos", "1 hoja de laurel", "1 cdta pimentón dulce", "3 cucharadas de AOVE", "Sal al final"], "preparacion": ["Remoja los judiones en agua fría 12h.", "Pon en olla con agua fría, chorizo, panceta, cebolla y laurel. Hierve y desespuma.", "'Asusta' con agua fría. Cocina tapado a fuego bajo 1h30.", "Dora ajos laminados con pimentón. Vierte sobre el guiso.", "Añade morcilla y reposa 10-15 min con el fuego apagado.", "Sal al final. Sirve con todo junto."]},
    {"nombre": "Crema Catalana", "ccaa": "Cataluña", "tiempo": "30 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Todo el año", "precio": 2.0, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": True, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Postre tradicional catalán de crema caramelizada.", "ingredientes": ["500 ml de leche entera", "4 yemas de huevo", "100 g de azúcar (80 g crema + 20 g quemar)", "20 g de maicena", "Piel de ½ limón", "1 rama de canela"], "preparacion": ["Infusiona leche con limón y canela a fuego medio. Cuela.", "Bate yemas con 80 g de azúcar hasta blanquear. Añade maicena.", "Vierte la leche caliente sobre yemas poco a poco removiendo.", "Vuelve al cazo y cocina removiendo 5-8 min hasta espesar.", "Reparte en cazuelitas. Enfría 2-3h en nevera.", "Antes de servir, espolvorea azúcar y quema con soplete hasta formar costra."]},
    {"nombre": "Canelones San Esteban", "ccaa": "Cataluña", "tiempo": "1h30-2h", "dificultad": "Difícil", "raciones": "2-3P", "temporada": "Invierno", "precio": 9.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": True, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Canelones tradicionales catalanes rellenos de carne asada.", "ingredientes": ["150 g carne picada ternera y 150 g cerdo", "150 g de pollo", "1 cebolla, 1 tomate, 2 ajos", "100 ml de vino blanco", "Laurel, tomillo, sal, pimienta, nuez moscada", "50 g de mantequilla y 50 g de harina", "500 ml de leche entera", "12-14 placas de canelones", "80 g de queso rallado"], "preparacion": ["Dora las carnes en cazuela. Añade cebolla, tomate y ajos. Sofríe 10 min.", "Vierte vino y evapora. Añade laurel y tomillo. Cocina 40-45 min a fuego suave.", "Pica fino, mezcla con 3-4 cucharadas de bechamel y reserva.", "Bechamel: funde mantequilla, añade harina, leche caliente poco a poco. Sazona.", "Remoja las placas, sécalas y rellena enrollando.", "Coloca en fuente con bechamel debajo y encima. Espolvorea queso.", "Hornea 15 min a 180 °C y gratina 5 min a 230 °C."]},
    {"nombre": "Escudella i Carn d'Olla", "ccaa": "Cataluña", "tiempo": "3h", "dificultad": "Difícil", "raciones": "2-3P", "temporada": "Invierno", "precio": 11.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Cocido catalán tradicional servido en dos vuelcos.", "ingredientes": ["300 g de pollo (muslos)", "200 g de costilla o panceta", "1 hueso de jamón", "1 butifarra blanca y 1 negra", "150 g de garbanzos", "1 patata, 2 zanahorias, ½ repollo, 1 puerro", "Sal, ajo y perejil", "2 litros de agua", "150 g de carne picada y 1 huevo (pilota)", "Harina", "80 g de galets o caracolas"], "preparacion": ["Pon pollo, costilla, hueso, zanahorias y puerro en olla con agua. Hierve y desespuma.", "Tras 30 min añade los garbanzos en malla.", "Forma pilotas con carne picada, huevo, ajo y perejil. Reboza en harina.", "Tras 1h añade patatas, repollo, butifarras y pilotas. Cocina 45-60 min.", "Cuela el caldo y cuece la pasta 10-12 min.", "Sirve sopa primero, luego carnes y verduras en fuente."]},
    {"nombre": "Caldereta de Cordero", "ccaa": "Extremadura", "tiempo": "1h30-2h", "dificultad": "Media", "raciones": "2-3P", "temporada": "Invierno", "precio": 9.0, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Cordero guisado tradicional extremeño con majado de hígado.", "ingredientes": ["700 g de cordero troceado", "100 g de hígado de cordero", "1 cebolla, 4 ajos", "1 pimiento morrón rojo", "1 cdta pimentón", "150 ml de vino blanco", "1 hoja de laurel", "AOVE, sal, pimienta, perejil", "Opcional: 1 rebanada de pan frito"], "preparacion": ["Fríe 2 ajos enteros en aceite. Reserva. Fríe el hígado. Reserva.", "Dora el cordero salpimentado por todos lados.", "Añade cebolla picada y laurel. Sofríe 10 min.", "Pimentón fuera del fuego. Añade vino y evapora. Cubre con agua y cocina 45-60 min tapado.", "Maja ajos fritos, hígado y pimiento morrón hasta pasta fina. Diluye con caldo.", "Incorpora el majado y cocina 10 min más. Sirve con pan."]},
    {"nombre": "Ajoblanco", "ccaa": "Extremadura", "tiempo": "20-25 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Verano", "precio": 1.5, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": True, "apto_vegano": True}, "descripcion": "Sopa fría refrescante de pan, ajo, almendras y aceite.", "ingredientes": ["3-4 dientes de ajo", "2-3 rebanadas de pan duro", "100 ml de AOVE", "1 cucharada de vinagre blanco", "Sal al gusto", "400-500 ml de agua muy fría", "1 tomate grande y ½ pepino"], "preparacion": ["Quita la corteza al pan, trocea y remoja 10 min.", "Maja los ajos con sal hasta pasta fina.", "Añade pan escurrido y maja. Incorpora aceite en hilo. Añade vinagre.", "Transfiere al bol y añade agua fría removiendo.", "Pica tomate y pepino en dados y añade.", "Enfría en nevera. Sirve muy frío."]},
    {"nombre": "Ajocano", "ccaa": "Extremadura", "tiempo": "25-30 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Verano", "precio": 2.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": True}, "descripcion": "Versión extremeña del ajoblanco con pimiento rojo asado.", "ingredientes": ["3 dientes de ajo", "2-3 rebanadas de pan duro", "1 pimiento rojo asado", "80 ml de AOVE", "1 cucharada de vinagre", "1 cdta pimentón de La Vera", "400-500 ml de agua fría", "Sal", "Tomate y pepino para acompañar"], "preparacion": ["Remoja el pan en agua 10 min.", "Bate ajos, pan, pimiento rojo asado, pimentón y sal con batidora.", "Añade aceite en hilo fino hasta obtener crema homogénea. Añade vinagre.", "Añade agua fría poco a poco hasta consistencia deseada.", "Enfría y sirve con tomate, pepino y pan."]},
    {"nombre": "Empanada Gallega", "ccaa": "Galicia", "tiempo": "1h45", "dificultad": "Media", "raciones": "2-3P", "temporada": "Todo el año", "precio": 5.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Empanada gallega tradicional rellena de atún con masa casera.", "ingredientes": ["300 g de harina de fuerza", "15 g de levadura fresca", "120 ml de agua tibia", "1 cdta sal", "1 huevo para pintar", "250 g de atún o bonito", "2 cebollas, 1 pimiento rojo, 1 verde", "3 cucharadas de tomate frito", "1 cdta pimentón", "100 ml de AOVE", "Sal"], "preparacion": ["Pocha cebollas en juliana muy lentamente. Añade pimientos 10 min. Apaga, añade pimentón y tomate. Mezcla con atún.", "Disuelve levadura en agua tibia. Mezcla con harina, sal y aceite del sofrito. Amasa 15 min. Reposa 1h.", "Divide la masa en dos. Estira en rectángulos. Coloca relleno en uno y cubre con otro.", "Sella bordes, haz agujero central y pinta con huevo.", "Hornea 40-45 min a 200 °C hasta dorar."]},
    {"nombre": "Raxo con Patatas", "ccaa": "Galicia", "tiempo": "30 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Todo el año", "precio": 6.0, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Lomo de cerdo adobado y salteado, servido con patatas.", "ingredientes": ["500 g de lomo de cerdo en tiras finas", "4-5 dientes de ajo picados", "Zumo de 1 limón", "1 cdta pimentón dulce y ½ cdta picante", "AOVE", "Sal y pimienta", "Perejil fresco picado", "3 patatas medianas para acompañar"], "preparacion": ["Corta el lomo en tiras. Mezcla con ajo, limón, pimentones, sal y pimienta. Macera 30 min mínimo.", "Pela y fríe las patatas en aceite hasta dorar.", "Saltea el lomo macerado a fuego fuerte 2-3 min por lado.", "Sirve patatas como base, raxo encima con sus jugos y perejil."]},
    {"nombre": "Tarta de Santiago", "ccaa": "Galicia", "tiempo": "1h", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Todo el año", "precio": 3.75, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": True, "frutos_secos": True, "apto_vegano": False}, "descripcion": "Tarta tradicional gallega de almendra molida sin harina.", "ingredientes": ["200 g de almendra molida", "150 g de azúcar", "3 huevos medianos", "Ralladura de 1 limón y ½ naranja", "1 cdta canela molida", "Mantequilla y harina para el molde", "Azúcar glas para decorar", "Plantilla con Cruz de Santiago"], "preparacion": ["Bate huevos con azúcar. Añade almendra, ralladuras y canela. Mezcla.", "Engrasa el molde redondo con mantequilla y harina.", "Vierte y hornea a 180 °C 35-40 min.", "Enfría completamente antes de desmoldar.", "Coloca la plantilla y espolvorea azúcar glas. Retira para revelar la Cruz."]},
    {"nombre": "Cocido Madrileño", "ccaa": "Madrid", "tiempo": "3h", "dificultad": "Difícil", "raciones": "2-3P", "temporada": "Invierno", "precio": 10.5, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Plato más representativo de Madrid, servido en tres vuelcos.", "ingredientes": ["200 g de garbanzos secos", "200 g de morcillo de ternera", "1 muslo de pollo", "100 g de tocino", "1 hueso de jamón serrano", "1 chorizo y 1 morcilla", "1 patata, 1 zanahoria, ½ repollo, 1 puerro", "2 L de agua, sal", "60 g de fideos finos"], "preparacion": ["Pon morcillo, pollo, tocino y hueso en olla con agua fría. Hierve y desespuma.", "Añade garbanzos en malla, zanahoria, puerro y sal. Cocina tapado 2h (35-40 min olla exprés).", "Añade patata cascada, repollo, chorizo y morcilla. Cocina 30-40 min más.", "Cuela el caldo y cuece los fideos 3-5 min.", "Sirve sopa primero, luego garbanzos con verduras, después las carnes."]},
    {"nombre": "Bocata de Calamares", "ccaa": "Madrid", "tiempo": "20-25 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Todo el año", "precio": 5.0, "favoritos": 0, "alergenos": {"gluten": True, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Bocadillo emblemático de Madrid con calamares rebozados y alioli.", "ingredientes": ["400 g de calamares (frescos o congelados)", "100 g de harina de trigo", "1 cdta pimentón dulce (opcional)", "Aceite para freír, sal", "2-3 barras de pan", "Para el alioli: 1 huevo, 150 ml aceite girasol, 1 ajo, zumo ½ limón, sal"], "preparacion": ["Limpia y corta calamares en anillas de 1 cm. Seca con papel.", "Alioli: bate huevo, ajo, limón y sal. Añade aceite en hilo fino sin mover la batidora.", "Sala las anillas y pásalas por harina con pimentón.", "Fríe en aceite muy caliente 1-2 min por tandas hasta dorar.", "Monta el bocata: pan, alioli y calamares calientes."]},
    {"nombre": "Ensalada Murciana", "ccaa": "Murcia", "tiempo": "15 min", "dificultad": "Fácil", "raciones": "2-3P", "temporada": "Verano", "precio": 3.25, "favoritos": 0, "alergenos": {"gluten": False, "lactosa": False, "frutos_secos": False, "apto_vegano": False}, "descripcion": "Ensalada fresca con tomate, atún, huevo y pimientos del piquillo.", "ingredientes": ["3 tomates maduros grandes", "1 lata de atún en aceite (120 g)", "½ cebolla tierna", "80 g de aceitunas negras sin hueso", "2 huevos cocidos", "1 lata pequeña de pimientos del piquillo", "AOVE, sal", "Opcional: pimentón dulce"], "preparacion": ["Cuece los huevos 10 min, enfría, pela y corta en cuartos.", "Corta los tomates en dados o rodajas. Sala.", "Pela y corta cebolla en juliana fina (puedes remojarla 10 min en agua salada).", "Monta sobre fuente: tomate, cebolla, atún, aceitunas, piquillos en tiras y huevo.", "Aliña con AOVE y sal. Refrigera 30 min antes de servir."]},
